30	export class FalImageModel implements ImageModelV3 {
31	  readonly specificationVersion = 'v3';
32	  readonly maxImagesPerCall = 1;
33	
34	  get provider(): string {
35	    return this.config.provider;
36	  }
37	
38	  constructor(
39	    readonly modelId: FalImageModelId,
40	    private readonly config: FalImageModelConfig,
41	  ) {}
42	
43	  private async getArgs({
44	    prompt,
45	    n,
46	    size,
47	    aspectRatio,
48	    seed,
49	    providerOptions,
50	    files,
51	    mask,
52	  }: Parameters<ImageModelV3['doGenerate']>[0]) {
53	    const warnings: Array<SharedV3Warning> = [];
54	
55	    let imageSize: FalImageSize | undefined;
56	    if (size) {
57	      const [width, height] = size.split('x').map(Number);
58	      imageSize = { width, height };
59	    } else if (aspectRatio) {
60	      imageSize = convertAspectRatioToSize(aspectRatio);
61	    }
62	
63	    const falOptions = await parseProviderOptions({
64	      provider: 'fal',
65	      providerOptions,
66	      schema: falImageModelOptionsSchema,
67	    });
68	
69	    const requestBody: Record<string, unknown> = {
70	      prompt,
71	      seed,
72	      image_size: imageSize,
73	      num_images: n,
74	    };
75	
76	    // Handle image editing: convert files to image_url or image_urls
77	    if (files != null && files.length > 0) {
78	      const useMultipleImages = falOptions?.useMultipleImages === true;
79	
80	      if (useMultipleImages) {
81	        // Use image_urls array for models that support multiple images (e.g., flux-2/edit)
82	        requestBody.image_urls = files.map(file =>
83	          convertImageModelFileToDataUri(file),
84	        );
85	      } else {
86	        // Use single image_url for standard image editing models
87	        requestBody.image_url = convertImageModelFileToDataUri(files[0]);
88	
89	        if (files.length > 1) {
90	          warnings.push({
91	            type: 'other',
92	            message:
93	              'Multiple input images provided but useMultipleImages is not enabled. ' +
94	              'Only the first image will be used. Set providerOptions.fal.useMultipleImages ' +
95	              'to true for models that support multiple images (e.g., fal-ai/flux-2/edit).',
96	          });
97	        }
98	      }
99	    }
100	
101	    // Handle mask for inpainting
102	    if (mask != null) {
103	      requestBody.mask_url = convertImageModelFileToDataUri(mask);
104	    }
105	
106	    if (falOptions) {
107	      const deprecatedKeys =
108	        '__deprecatedKeys' in falOptions
109	          ? (falOptions.__deprecatedKeys as string[])
110	          : undefined;
111	
112	      if (deprecatedKeys && deprecatedKeys.length > 0) {
113	        warnings.push({
114	          type: 'other',
115	          message: `The following provider options use deprecated snake_case and will be removed in @ai-sdk/fal v2.0. Please use camelCase instead: ${deprecatedKeys
116	            .map(key => {
117	              const camelCase = key.replace(/_([a-z])/g, (_, letter) =>
118	                letter.toUpperCase(),
119	              );
120	              return `'${key}' (use '${camelCase}')`;
121	            })
122	            .join(', ')}`,
123	        });
124	      }
125	
126	      const fieldMapping: Record<string, string> = {
127	        imageUrl: 'image_url',
128	        maskUrl: 'mask_url',
129	        guidanceScale: 'guidance_scale',
130	        numInferenceSteps: 'num_inference_steps',
131	        enableSafetyChecker: 'enable_safety_checker',
132	        outputFormat: 'output_format',
133	        syncMode: 'sync_mode',
134	        safetyTolerance: 'safety_tolerance',
135	      };
136	
137	      for (const [key, value] of Object.entries(falOptions)) {
138	        if (key === '__deprecatedKeys') continue;
139	        if (key === 'useMultipleImages') continue; // Don't send to API
140	        const apiKey = fieldMapping[key] ?? key;
141	
142	        if (value !== undefined) {
143	          requestBody[apiKey] = value;
144	        }
145	      }
146	    }
147	
148	    return { requestBody, warnings } as const;
149	  }
150	
151	  async doGenerate(
152	    options: Parameters<ImageModelV3['doGenerate']>[0],
153	  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
154	    const { requestBody, warnings } = await this.getArgs(options);
155	
156	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
157	    const { value, responseHeaders } = await postJsonToApi({
158	      url: `${this.config.baseURL}/${this.modelId}`,
159	      headers: combineHeaders(
160	        await resolve(this.config.headers),
161	        options.headers,
162	      ),
163	      body: requestBody,
164	      failedResponseHandler: falFailedResponseHandler,
165	      successfulResponseHandler: createJsonResponseHandler(
166	        falImageResponseSchema,
167	      ),
168	      abortSignal: options.abortSignal,
169	      fetch: this.config.fetch,
170	    });
171	
172	    const {
173	      images: targetImages,
174	      // prompt is just passed through and not a revised prompt per image
175	      prompt: _prompt,
176	      // NSFW information is normalized merged into `providerMetadata.fal.images`
177	      has_nsfw_concepts,
178	      nsfw_content_detected,
179	      // pass through other properties to providerMetadata
180	      ...responseMetaData
181	    } = value;
182	
183	    // download the images:
184	    const downloadedImages = await Promise.all(
185	      targetImages.map(image =>
186	        this.downloadImage(image.url, options.abortSignal),
187	      ),
188	    );
189	
190	    return {
191	      images: downloadedImages,
192	      warnings,
193	      response: {
194	        modelId: this.modelId,
195	        timestamp: currentDate,
196	        headers: responseHeaders,
197	      },
198	      providerMetadata: {
199	        fal: {
200	          images: targetImages.map((image, index) => {
201	            const {
202	              url,
203	              content_type: contentType,
204	              file_name: fileName,
205	              file_data: fileData,
206	              file_size: fileSize,
207	              ...imageMetaData
208	            } = image;
209	
210	            const nsfw =
211	              has_nsfw_concepts?.[index] ?? nsfw_content_detected?.[index];
212	
213	            return {
214	              ...imageMetaData,
215	              ...removeOnlyUndefined({
216	                contentType,
217	                fileName,
218	                fileData,
219	                fileSize,
220	                nsfw,
221	              }),
222	            };
223	          }),
224	          ...responseMetaData,
225	        },
226	      },
227	    };
228	  }
229	
230	  private async downloadImage(
231	    url: string,
232	    abortSignal: AbortSignal | undefined,
233	  ): Promise<Uint8Array> {
234	    const { value: response } = await getFromApi({
235	      url,
236	      // No specific headers should be needed for this request as it's a
237	      // generated image provided by fal.ai.
238	      abortSignal,
239	      failedResponseHandler: createStatusCodeErrorResponseHandler(),
240	      successfulResponseHandler: createBinaryResponseHandler(),
241	      fetch: this.config.fetch,
242	    });
243	    return response;
244	  }
245	}
246	
247	function removeOnlyUndefined<T extends Record<string, unknown>>(obj: T) {
248	  return Object.fromEntries(
249	    Object.entries(obj).filter(([, v]) => v !== undefined),
250	  ) as Partial<T>;
251	}
252	
253	/**
254	 * Converts an aspect ratio to an image size compatible with fal.ai APIs.
255	 * @param aspectRatio - The aspect ratio to convert.
256	 * @returns The image size.
257	 */
258	function convertAspectRatioToSize(
259	  aspectRatio: `${number}:${number}`,
260	): FalImageSize | undefined {
261	  switch (aspectRatio) {
262	    case '1:1':
263	      return 'square_hd';
264	    case '16:9':
265	      return 'landscape_16_9';
266	    case '9:16':
267	      return 'portrait_16_9';
268	    case '4:3':
269	      return 'landscape_4_3';
270	    case '3:4':
271	      return 'portrait_4_3';
272	    case '16:10':
273	      return { width: 1280, height: 800 };
274	    case '10:16':
275	      return { width: 800, height: 1280 };
276	    case '21:9':
277	      return { width: 2560, height: 1080 };
278	    case '9:21':
279	      return { width: 1080, height: 2560 };
280	  }
281	  return undefined;
282	}
283	
284	// Validation error has a particular payload to inform the exact property that is invalid
285	const falValidationErrorSchema = z.object({
286	  detail: z.array(
287	    z.object({
288	      loc: z.array(z.string()),
289	      msg: z.string(),
290	      type: z.string(),
291	    }),
292	  ),
293	});
294	
295	type ValidationError = z.infer<typeof falValidationErrorSchema>;
296	
297	// Other errors have a message property
298	const falHttpErrorSchema = z.object({
299	  message: z.string(),
300	});
301	
302	const falErrorSchema = z.union([falValidationErrorSchema, falHttpErrorSchema]);
303	
304	const falImageSchema = z.object({
305	  url: z.string(),
306	  width: z.number().nullish(),
307	  height: z.number().nullish(),
308	  // e.g. https://fal.ai/models/fal-ai/fashn/tryon/v1.6/api#schema-output
309	  content_type: z.string().nullish(),
310	  // e.g. https://fal.ai/models/fal-ai/flowedit/api#schema-output
311	  file_name: z.string().nullish(),
312	  file_data: z.string().optional(),
313	  file_size: z.number().nullish(),
314	});
315	
316	// https://fal.ai/models/fal-ai/lora/api#type-File
317	const loraFileSchema = z.object({
318	  url: z.string(),
319	  content_type: z.string().optional(),
320	  file_name: z.string().nullable().optional(),
321	  file_data: z.string().optional(),
322	  file_size: z.number().nullable().optional(),
323	});
324	
325	const commonResponseSchema = z.object({
326	  timings: z
327	    .object({
328	      inference: z.number().optional(),
329	    })
330	    .optional(),
331	  seed: z.number().optional(),
332	  has_nsfw_concepts: z.array(z.boolean()).optional(),
333	  prompt: z.string().optional(),
334	  // https://fal.ai/models/fal-ai/lcm/api#schema-output
335	  nsfw_content_detected: z.array(z.boolean()).optional(),
336	  num_inference_steps: z.number().optional(),
337	  // https://fal.ai/models/fal-ai/lora/api#schema-output
338	  debug_latents: loraFileSchema.optional(),
339	  debug_per_pass_latents: loraFileSchema.optional(),
340	});
341	
342	// Most FAL image models respond with an array of images, but some have a response
343	// with a single image, e.g. https://fal.ai/models/easel-ai/easel-avatar/api#schema-output
344	const base = z.looseObject(commonResponseSchema.shape);
345	const falImageResponseSchema = z
346	  .union([
347	    base.extend({ images: z.array(falImageSchema) }),
348	    base.extend({ image: falImageSchema }),
349	  ])
350	  .transform(v => ('images' in v ? v : { ...v, images: [v.image] }))
351	  .pipe(base.extend({ images: z.array(falImageSchema) }));
352	
353	function isValidationError(error: unknown): error is ValidationError {
354	  return falValidationErrorSchema.safeParse(error).success;
355	}
356	
357	const falFailedResponseHandler = createJsonErrorResponseHandler({
358	  errorSchema: falErrorSchema,
359	  errorToMessage: error => {
360	    if (isValidationError(error)) {
361	      return error.detail
362	        .map(detail => `${detail.loc.join('.')}: ${detail.msg}`)
363	        .join('\n');
364	    }
365	    return error.message ?? 'Unknown fal error';
366	  },
367	});
