import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const TEST_BASE_URL = 'https://api.example.com';
const TEST_GENERATE_URL = `${TEST_BASE_URL}/generate`;
const TEST_IMAGE_URL = `${TEST_BASE_URL}/image.png`;

const TEST_DATE = new Date('2024-01-01T00:00:00Z');

function createModel(
  modelId = 'pixelart-v1',
  override: Partial<ConstructorParameters<typeof PixelArtImageModel>[1]> = {},
) {
  return new PixelArtImageModel(modelId, {
    provider: 'pixelart.image',
    baseURL: TEST_BASE_URL,
    headers: { Authorization: 'Bearer test-key' },
    _internal: { currentDate: () => TEST_DATE },
    ...override,
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    [TEST_GENERATE_URL]: {
      response: {
        type: 'json-value',
        body: {
          images: [{ url: TEST_IMAGE_URL }],
        },
      },
    },
    [TEST_IMAGE_URL]: {
      response: {
        type: 'binary',
        body: Buffer.from('fake-image-bytes'),
      },
    },
  });

  describe('specificationVersion', () => {
    it('should be v3', () => {
      expect(createModel().specificationVersion).toBe('v3');
    });
  });

  describe('provider', () => {
    it('should return provider string', () => {
      expect(createModel().provider).toBe('pixelart.image');
    });
  });

  describe('maxImagesPerCall', () => {
    it('should be 1', () => {
      expect(createModel().maxImagesPerCall).toBe(1);
    });
  });

  describe('doGenerate', () => {
    it('should POST to baseURL/generate', async () => {
      await createModel().doGenerate({
        prompt: 'a pixel art cat',
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        abortSignal: undefined,
        headers: {},
        files: undefined,
        mask: undefined,
      });

      expect(server.calls[0].requestUrl).toBe(TEST_GENERATE_URL);
      expect(server.calls[0].requestMethod).toBe('POST');
    });

    it('should include prompt, n, seed, and model in request body', async () => {
      await createModel('pixelart-v2').doGenerate({
        prompt: 'a retro robot',
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
        abortSignal: undefined,
        headers: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        model: 'pixelart-v2',
        prompt: 'a retro robot',
        n: 1,
        seed: 42,
      });
    });

    it('should split size into width and height', async () => {
      await createModel().doGenerate({
        prompt: 'a pixel landscape',
        n: 1,
        size: '512x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        abortSignal: undefined,
        headers: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        width: 512,
        height: 256,
      });
    });

    it('should not include width/height when size is not provided', async () => {
      await createModel().doGenerate({
        prompt: 'a pixel art scene',
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        abortSignal: undefined,
        headers: {},
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('width');
      expect(body).not.toHaveProperty('height');
    });

    it('should pass style from providerOptions', async () => {
      await createModel().doGenerate({
        prompt: 'an 8-bit dungeon',
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { style: '8bit' } },
        abortSignal: undefined,
        headers: {},
        files: undefined,
