import { NoSuchModelError } from '@ai-sdk/provider';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';
import { createPixelArt } from './pixelart-provider';

describe('createPixelArt', () => {
  describe('imageModel / image', () => {
    it('imageModel() returns a PixelArtImageModel', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.imageModel('pixelart-v1');
      expect(model).toBeInstanceOf(PixelArtImageModel);
    });

    it('image() returns a PixelArtImageModel', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.image('pixelart-v2');
      expect(model).toBeInstanceOf(PixelArtImageModel);
    });

    it('model has the correct modelId', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.imageModel('pixelart-v2');
      expect(model.modelId).toBe('pixelart-v2');
    });

    it('model has the correct provider string', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.imageModel('pixelart-v1');
      expect(model.provider).toBe('pixelart.image');
    });

    it('accepts arbitrary model id strings', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.imageModel('custom-model-id');
      expect(model.modelId).toBe('custom-model-id');
    });
  });

  describe('languageModel', () => {
    it('throws NoSuchModelError', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(() => provider.languageModel('gpt-4')).toThrow(NoSuchModelError);
    });

    it('includes the modelId in the error', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      try {
        provider.languageModel('gpt-4');
      } catch (error) {
        expect(NoSuchModelError.isInstance(error)).toBe(true);
        if (NoSuchModelError.isInstance(error)) {
          expect(error.modelId).toBe('gpt-4');
          expect(error.modelType).toBe('languageModel');
        }
      }
    });
  });

  describe('embeddingModel', () => {
    it('throws NoSuchModelError', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(() => provider.embeddingModel('text-embedding-3')).toThrow(
        NoSuchModelError,
      );
    });

    it('includes the modelId in the error', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      try {
        provider.embeddingModel('text-embedding-3');
      } catch (error) {
        expect(NoSuchModelError.isInstance(error)).toBe(true);
        if (NoSuchModelError.isInstance(error)) {
          expect(error.modelId).toBe('text-embedding-3');
          expect(error.modelType).toBe('embeddingModel');
        }
      }
    });
  });

  describe('specificationVersion', () => {
    it('is v3', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(provider.specificationVersion).toBe('v3');
    });
  });

  describe('custom baseURL', () => {
    it('uses custom baseURL when provided', () => {
      const provider = createPixelArt({
        apiKey: 'test-key',
        baseURL: 'https://custom.api.example.com/v2',
      });
      const model = provider.imageModel('pixelart-v1') as PixelArtImageModel;
      // Provider correctly stores model — modelId is visible
      expect(model.modelId).toBe('pixelart-v1');
    });
  });
});

